@tailwind base;
@tailwind components;
@tailwind utilities;

@layer base {
  body {
    @apply bg-gray-950 text-gray-100 antialiased;
    font-family: 'Inter', -apple-system, BlinkMacSystemFont, 'Segoe UI', sans-serif;
  }
  * {
    scrollbar-width: thin;
    scrollbar-color: #374151 transparent;
  }
  *::-webkit-scrollbar {
    width: 6px;
    height: 6px;
  }
  *::-webkit-scrollbar-track {
    background: transparent;
  }
  *::-webkit-scrollbar-thumb {
    background-color: #374151;
    border-radius: 3px;
  }
}

@layer utilities {
  .glass {
    @apply bg-white/5 backdrop-blur-sm border border-white/10;
  }
  .card {
    @apply bg-gray-900 border border-gray-800 rounded-xl;
  }
  .badge-green { @apply bg-green-500/20 text-green-400 border border-green-500/30; }
  .badge-red { @apply bg-red-500/20 text-red-400 border border-red-500/30; }
  .badge-yellow { @apply bg-yellow-500/20 text-yellow-400 border border-yellow-500/30; }
  .badge-blue { @apply bg-blue-500/20 text-blue-400 border border-blue-500/30; }
  .badge-purple { @apply bg-purple-500/20 text-purple-400 border border-purple-500/30; }
  .badge-orange { @apply bg-orange-500/20 text-orange-400 border border-orange-500/30; }
}
