            {group.items.map(item => {
              const Icon = item.icon;
              const active = activeModule === item.id;
              const badgeColors: Record<string, string> = {
                purple: 'bg-purple-600 text-white',
                blue: 'bg-blue-600 text-white',
                green: 'bg-green-600 text-white',
