    19→
    20→const MONTH_ABBR = ['Jan','Feb','Mar','Apr','May','Jun','Jul','Aug','Sep','Oct','Nov','Dec'];
    21→
    22→function buildChartData(invoices: AnyRow[]) {
    23→  const now = new Date();
    24→  const months: { month: string; revenue: number; profit: number }[] = [];
    25→  for (let i = 5; i >= 0; i--) {
    26→    const d = new Date(now.getFullYear(), now.getMonth() - i, 1);
    27→    months.push({ month: MONTH_ABBR[d.getMonth()], revenue: 0, profit: 0 });
    28→  }
    29→  invoices.filter(inv => inv.status === 'paid').forEach(inv => {
    30→    const dateStr = String(inv.issueDate ?? inv.issue_date ?? '');
    31→    if (!dateStr) return;
    32→    const d = new Date(dateStr);
    33→    const mIdx = months.findIndex(m => m.month === MONTH_ABBR[d.getMonth()] && d.getFullYear() === new Date().getFullYear());
    34→    if (mIdx !== -1) {
    35→      months[mIdx].revenue += Number(inv.amount ?? 0);
    36→      months[mIdx].profit  += Number(inv.amount ?? 0) * 0.23;
    37→    }
    38→  });
    39→  return months;
    40→}
    41→
    42→export function Dashboard({ setModule }: DashboardProps) {
    43→  const [activeProject, setActiveProject] = useState<string | null>(null);
    44→
    45→  const { data: rawProjects  = [] } = useProjects.useList();
    46→  const { data: rawInvoices  = [] } = useInvoices.useList();
    47→  const { data: rawTeam      = [] } = useTeam.useList();
    48→  const { data: rawSafety    = [] } = useSafety.useList();
