    61→  const totalRevenue     = invoices.filter(i => i.status === 'paid').reduce((s, i) => s + Number(i.amount ?? 0), 0);
    62→  const outstanding      = invoices.filter(i => i.status === 'sent' || i.status === 'overdue').reduce((s, i) => s + Number(i.amount ?? 0), 0);
    63→  const workerCount      = team.filter(m => m.status === 'active' || !m.status).length;
