    76→    { label:'Active Projects',   value:String(activeProjects.length), change:'This month',      isPositive:true,  icon:FolderOpen,    iconBg:'bg-purple-500/20',  iconColor:'text-purple-400' },
    77→    { label:'Workers On Site',   value:String(workerCount),      change:'Team total',      isPositive:true,  icon:HardHat,       iconBg:'bg-green-500/20',   iconColor:'text-green-400'  },
