   129→  });
   130→
   131→  // Sort by date descending and take top 6
   132→  const recentActivities = activityFeed
   133→    .sort((a, b) => (b.sortKey > a.sortKey ? 1 : b.sortKey < a.sortKey ? -1 : 0))
   134→    .slice(0, 6)
   135→    .map(a => {
