          backgroundSize: '24px 24px',
        }} />
        {/* Amber left accent */}
        <div style={{
          position: 'absolute', left: 0, top: 0, bottom: 0, width: '3px',
          background: 'linear-gradient(180deg, var(--amber-400), var(--amber-600))',
